class DesfazerBaixaDialog extends StatelessWidget {
  final DateTime dataBaixa;
  final double valorBaixa;
  final String contaLabel;
  final String formaPagamentoLabel;
  final VoidCallback? onSuccess; // opcional: callback após sucesso

  const DesfazerBaixaDialog({
    super.key,
    required this.dataBaixa,
    required this.valorBaixa,
    required this.contaLabel,
    required this.formaPagamentoLabel,
    this.onSuccess,
  });

  static Future<void> show(
    BuildContext context, {
    required DateTime dataBaixa,
    required double valorBaixa,
    required String contaLabel,
    required String formaPagamentoLabel,
    VoidCallback? onSuccess,
  }) {
    return BaixaDialogBase.showDialogWithTransition(
      context: context,
      barrierLabel: 'Desfazer Baixa',
      child: DesfazerBaixaDialog(
        dataBaixa: dataBaixa,
        valorBaixa: valorBaixa,
        contaLabel: contaLabel,
        formaPagamentoLabel: formaPagamentoLabel,
        onSuccess: onSuccess,
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final colors = CustomColors();

    return AlertDialog(
      backgroundColor: GridColors.dialogBackground.withOpacity(0.95),
      elevation: 12,
      shadowColor: Colors.black26,
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
      title: Row(
        children: [
          const Icon(Icons.undo, color: GridColors.primary),
          const SizedBox(width: 8),
          Text('Desfazer Baixa',
              style: TextStyle(color: colors.getDarkGreenBorder(), fontWeight: FontWeight.bold)),
        ],
      ),
      content: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          _infoTile('Data da Baixa', _fmtDate(dataBaixa)),
          const SizedBox(height: 8),
          _infoTile('Valor da Baixa', _fmtCurrency(valorBaixa)),
          const SizedBox(height: 8),
          _infoTile('Conta', contaLabel),
          const SizedBox(height: 8),
          _infoTile('Forma de Pagamento', formaPagamentoLabel),
          const SizedBox(height: 12),
          const Divider(),
          const SizedBox(height: 6),
          const Text(
            'Tem certeza que deseja desfazer esta baixa? Esta ação não pode ser desfeita.',
            style: TextStyle(fontSize: 13),
          ),
        ],
      ),
      actions: [
        TextButton(
          style: TextButton.styleFrom(
            backgroundColor: colors.getCancelButtonColor(),
            foregroundColor: colors.getButtonTextColor(),
          ),
          onPressed: () => Navigator.pop(context),
          child: const Text('Cancelar'),
        ),
        ElevatedButton.icon(
          icon: const Icon(Icons.undo),
          style: ElevatedButton.styleFrom(
            backgroundColor: colors.getConfirmButtonColor(),
            foregroundColor: colors.getButtonTextColor(),
          ),
          onPressed: () async {
            // TODO: chame seu endpoint de desfazer aqui
            // final res = await NetworkCaller().postRequest(ApiLinks.desfazerBaixaContaX(id), {});
            // if (res.isSuccess) { ... }

            ScaffoldMessenger.of(context).showSnackBar(
              SnackBar(
                content: const Text('Baixa desfeita com sucesso!'),
                backgroundColor: colors.getShowSnackBarSuccess(),
              ),
            );
            Navigator.pop(context, true);
            onSuccess?.call();
          },
          label: const Text('Desfazer'),
        ),
      ],
    );
  }

  Widget _infoTile(String label, String value) {
    return Row(
      children: [
        Expanded(
          child: Text(label, style: const TextStyle(fontWeight: FontWeight.w600)),
        ),
        const SizedBox(width: 12),
        Flexible(
          child: Text(
            value,
            textAlign: TextAlign.right,
            overflow: TextOverflow.ellipsis,
          ),
        ),
      ],
    );
  }

  String _fmtDate(DateTime d) =>
      '${d.day.toString().padLeft(2, '0')}/${d.month.toString().padLeft(2, '0')}/${d.year}';

  String _fmtCurrency(double v) => 'R\$ ${v.toStringAsFixed(2)}';
}
